function formatCompactNativeDateTimeValue(
  type: "date" | "time",
  value: string,
  placeholder: string,
) {
  if (!value) {
    return placeholder;
  }

  if (type === "time") {
    return value.slice(0, 5) || placeholder;
  }

  const match = /^(\d{4})-(\d{2})-(\d{2})/.exec(value);
  return match ? `${match[2]}/${match[3]}` : value;
}

function CompactNativeDateTimeField({
  id,
  type,
  value,
  onChange,
  className,
  placeholder,
  disabled = false,
  displayValue,
}: {
  id: string;
  type: "date" | "time";
  value: string;
  onChange: React.ChangeEventHandler<HTMLInputElement>;
  className: string;
  placeholder: string;
  disabled?: boolean;
  displayValue?: string;
}) {
  const resolvedDisplayValue = displayValue ?? formatCompactNativeDateTimeValue(
    type,
    value,
    placeholder,
  );

  return (
    <div className="relative min-w-0 w-full">
      <input
        id={id}
        type={type}
        value={value}
        onChange={onChange}
        disabled={disabled}
        className={cn(
          "peer absolute inset-0 z-10 h-full w-full min-w-0 max-w-full appearance-none opacity-0 focus:outline-none",
          disabled ? "pointer-events-none cursor-not-allowed" : "cursor-pointer",
        )}
      />
      <div
        aria-hidden="true"
        className={cn(
          className,
          "relative z-0 flex w-full min-w-0 items-center overflow-hidden leading-none peer-focus-visible:border-zinc-400/50",
          disabled &&
            "cursor-not-allowed border-white/[0.07] bg-white/[0.025] text-white/30",
        )}
      >
        <span className="block min-w-0 truncate">{resolvedDisplayValue}</span>
      </div>
    </div>
  );
}

