  const buildSearchUrl = useCallback(
    (cursor: FabSearchCursor | null) => {
      const trimmed = searchQuery.trim();
      const params = new URLSearchParams();
      if (trimmed.length > 0) {
        params.set("q", trimmed);
      }
      params.set("sort", overlaySortMode);
      if (cursor) {
        params.set("cursorStartUtc", cursor.startUtc);
        params.set("cursorSourceType", cursor.sourceType);
        params.set("cursorSourceId", cursor.sourceId);
      }
      return `/api/schedule/search?${params.toString()}`;
    },
    [overlaySortMode, searchQuery],
  );

  const runSearch = useCallback(
    async ({
      cursor,
      append,
      signal,
    }: {
      cursor: FabSearchCursor | null;
      append: boolean;
      signal?: AbortSignal;
    }) => {
      const searchKey = buildSearchCacheKey();
      const response = await fetch(buildSearchUrl(cursor), { signal });
      if (!response.ok) {
        throw new Error(`Request failed: ${response.status}`);
      }
      const payload = (await response.json()) as {
        results?: FabSearchResult[];
        nextCursor?: {
          startUtc?: string | null;
          sourceType?: "PROJECT" | "HABIT" | null;
          sourceId?: string | null;
        } | null;
      };
      const nextCursor =
        payload.nextCursor?.startUtc &&
        payload.nextCursor?.sourceType &&
        payload.nextCursor?.sourceId
          ? {
              startUtc: payload.nextCursor.startUtc,
              sourceType: payload.nextCursor.sourceType,
              sourceId: payload.nextCursor.sourceId,
            }
          : null;
      if (!signal?.aborted) {
        const receivedResults = payload.results ?? [];
        setSearchResults((prev) => {
          const nextResults = append
            ? [...prev, ...receivedResults]
            : receivedResults;
          activeSearchKeyRef.current = searchKey;
          searchCacheRef.current = {
            key: searchKey,
            results: nextResults,
            cursor: nextCursor,
          };
          return nextResults;
        });
        setSearchCursor(nextCursor);
      }
    },
    [buildSearchCacheKey, buildSearchUrl],
  );

  // Scheduler runs should come from explicit scheduler flows, not generic object saves.
  const notifySchedulerOfChange = useCallback(async () => {
    try {
      const timeZone =
        typeof Intl !== "undefined"
          ? (Intl.DateTimeFormat().resolvedOptions().timeZone ?? null)
          : null;
      const payload = {
        localNow: new Date().toISOString(),
        timeZone,
        utcOffsetMinutes: -new Date().getTimezoneOffset(),
        mode: { type: "REGULAR" },
        writeThroughDays: 1,
      };
      await fetch("/api/scheduler/run", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
    } catch (error) {
      console.error("Failed to notify scheduler", error);
    }
  }, []);

  const runDynamicOverlayScheduler = useCallback(
    async (dynamicOverlayEndTime: Date) => {
      const localNow = new Date();
      const timeZone =
        typeof Intl !== "undefined"
          ? (Intl.DateTimeFormat().resolvedOptions().timeZone ?? null)
          : null;
      const writeThroughDays = getDynamicOverlaySchedulerWriteThroughDays(
        dynamicOverlayEndTime,
        localNow,
      );
      const payload = {
        localTimeIso: localNow.toISOString(),
        timeZone,
        utcOffsetMinutes: -localNow.getTimezoneOffset(),
        mode: { type: "REGULAR" },
        writeThroughDays,
      };

      try {
        dispatchScheduleSchedulerRunningChange(true);
        console.info("Running dynamic overlay scheduler", payload);
        const response = await fetch("/api/scheduler/run", {
          method: "POST",
          cache: "no-store",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });

        console.info("Dynamic overlay scheduler response", {
          ok: response.ok,
          status: response.status,
          statusText: response.statusText,
        });

        if (!response.ok) {
          throw new Error(await readSchedulerRunErrorMessage(response));
        }

        return writeThroughDays;
      } catch (error) {
        console.error("Dynamic overlay scheduler request failed", error);
        throw error;
      } finally {
        dispatchScheduleSchedulerRunningChange(false);
      }
    },
    [],
  );

